module  omsp_sync_cell (
    data_out,                      
    clk,                           
    data_in,                       
    rst                            
);
output              data_out;      
input               clk;          
input               data_in;      
input               rst;          
reg  [1:0] sync_reg;
always @(posedge clk or posedge rst)
  if (rst) sync_reg <=  2'b00;
  else     sync_reg <=  {sync_reg[0], data_in};
assign     data_out   =   sync_reg[1];
endmodule
